content:
Basic actions panel:

import {ActionsPanel} from '@gravity-ui/uikit';

<ActionsPanel
  actions={[
    {id: 'edit', text: 'Edit', handler: () => {}},
    {id: 'delete', text: 'Delete', handler: () => {}, theme: 'danger'},
  ]}
  onClose={() => {}}
/>

Arrow pointing up (expanded state):

import {ArrowToggle} from '@gravity-ui/uikit';

<ArrowToggle direction="top" size={16} />

Controlled checkbox:

import {Checkbox} from '@gravity-ui/uikit';

const [checked, setChecked] = React.useState(false);

<Checkbox checked={checked} onUpdate={setChecked} content="Accept terms" />

Indeterminate checkbox:

<Checkbox indeterminate content="Select all" />

Copy URL button:

import {ClipboardButton} from '@gravity-ui/uikit';

<ClipboardButton text="https://example.com" />

Clipboard icon showing success state:

import {ClipboardIcon} from '@gravity-ui/uikit';

<ClipboardIcon status="success" size={16} />

Custom copy button using render prop:

import {CopyToClipboard} from '@gravity-ui/uikit';

<CopyToClipboard text="Text to copy" timeout={2000}>
  {(status) => (
    <button>
      {status === 'success' ? 'Copied!' : 'Copy'}
    </button>
  )}
</CopyToClipboard>

Simple dropdown menu:

import {DropdownMenu} from '@gravity-ui/uikit';

<DropdownMenu
  items={[
    {text: 'Edit', action: () => handleEdit()},
    {text: 'Delete', action: () => handleDelete(), theme: 'danger'},
  ]}
/>

Grouped menu items:

<DropdownMenu
  items={[
    [{text: 'Copy'}, {text: 'Paste'}],
    [{text: 'Delete', theme: 'danger'}],
  ]}
/>

File preview with remove action:

import {FilePreview} from '@gravity-ui/uikit';
import {TrashBin} from '@gravity-ui/icons';

<FilePreview
  file={file}
  actions={[
    {
      icon: <Icon data={TrashBin} size={14} />,
      title: 'Remove',
      onClick: () => removeFile(file),
    },
  ]}
/>

Keyboard shortcut display:

import {Hotkey} from '@gravity-ui/uikit';

<Hotkey value="mod+k" />

Basic icon usage:

import {Icon} from '@gravity-ui/uikit';
import {Gear} from '@gravity-ui/icons';

<Icon data={Gear} size={16} />

Simple list with click handler:

import {List} from '@gravity-ui/uikit';

<List
  items={['Apple', 'Banana', 'Cherry']}
  renderItem={(item) => <span>{item}</span>}
  onItemClick={(item) => console.log(item)}
/>

Medium spinner:

import {Loader} from '@gravity-ui/uikit';

<Loader size="m" />
